                if (clientOAuth2Client.RefreshTokenGrantRefreshTokenLifespanOption.Value != null)
                    writer.WriteString("refresh_token_grant_refresh_token_lifespan", clientOAuth2Client.RefreshTokenGrantRefreshTokenLifespan);
                else
                    writer.WriteNull("refresh_token_grant_refresh_token_lifespan");

            if (clientOAuth2Client.RegistrationAccessTokenOption.IsSet)
                writer.WriteString("registration_access_token", clientOAuth2Client.RegistrationAccessToken);

            if (clientOAuth2Client.RegistrationClientUriOption.IsSet)
                writer.WriteString("registration_client_uri", clientOAuth2Client.RegistrationClientUri);

            if (clientOAuth2Client.RequestObjectSigningAlgOption.IsSet)
                writer.WriteString("request_object_signing_alg", clientOAuth2Client.RequestObjectSigningAlg);

            if (clientOAuth2Client.RequestUrisOption.IsSet)
            {
                writer.WritePropertyName("request_uris");
                JsonSerializer.Serialize(writer, clientOAuth2Client.RequestUris, jsonSerializerOptions);
            }
            if (clientOAuth2Client.ResponseTypesOption.IsSet)
            {
                writer.WritePropertyName("response_types");
                JsonSerializer.Serialize(writer, clientOAuth2Client.ResponseTypes, jsonSerializerOptions);
            }
            if (clientOAuth2Client.ScopeOption.IsSet)
                writer.WriteString("scope", clientOAuth2Client.Scope);

            if (clientOAuth2Client.SectorIdentifierUriOption.IsSet)
                writer.WriteString("sector_identifier_uri", clientOAuth2Client.SectorIdentifierUri);

            if (clientOAuth2Client.SkipConsentOption.IsSet)
                writer.WriteBoolean("skip_consent", clientOAuth2Client.SkipConsentOption.Value!.Value);

            if (clientOAuth2Client.SkipLogoutConsentOption.IsSet)
                writer.WriteBoolean("skip_logout_consent", clientOAuth2Client.SkipLogoutConsentOption.Value!.Value);

            if (clientOAuth2Client.SubjectTypeOption.IsSet)
                writer.WriteString("subject_type", clientOAuth2Client.SubjectType);

            if (clientOAuth2Client.TokenEndpointAuthMethodOption.IsSet)
                writer.WriteString("token_endpoint_auth_method", clientOAuth2Client.TokenEndpointAuthMethod);

            if (clientOAuth2Client.TokenEndpointAuthSigningAlgOption.IsSet)
                writer.WriteString("token_endpoint_auth_signing_alg", clientOAuth2Client.TokenEndpointAuthSigningAlg);

            if (clientOAuth2Client.TosUriOption.IsSet)
                writer.WriteString("tos_uri", clientOAuth2Client.TosUri);

            if (clientOAuth2Client.UpdatedAtOption.IsSet)
                writer.WriteString("updated_at", clientOAuth2Client.UpdatedAtOption.Value!.Value.ToString(UpdatedAtFormat));

            if (clientOAuth2Client.UserinfoSignedResponseAlgOption.IsSet)
                writer.WriteString("userinfo_signed_response_alg", clientOAuth2Client.UserinfoSignedResponseAlg);
        }
    }
}
